const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/data/jobs/test.json', 'utf8'));
return [{ json: { config, source: config.sources[0] } }];

const config = $('Load Config').first().json.config;
const article = $input.first().json;

if (!article || !article.title) throw new Error('No article returned from RSS feed');

const title = article.title || 'Untitled';
const description = article.contentSnippet || article.content || article.summary || '';
const link = article.link || '';

const systemPrompt = config.system_prompt;
const userPrompt = `${config.user_prompt_format}\n\n- **${title}**: ${description.substring(0, 400)}`;

return [{
  json: {
    config,
    articleTitle: title,
    articleLink: link,
    // Pre-build the Ollama request body to avoid n8n expression serialisation issues
    ollamaBody: JSON.stringify({
      model: config.model,
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: userPrompt }
      ],
      stream: false,
      options: config.ollama_options || {}
    })
  }
}];

const config = $('Load Config').first().json.config;
const response = $input.first().json;
const promptData = $('Prepare Prompt').first().json;

const summary = response?.message?.content || 'No summary returned.';

let webhookUrl = config?.discord?.webhook_url || '';
const envVar = config?.discord?.webhook_url_env;
if (!webhookUrl && envVar && $env[envVar]) webhookUrl = $env[envVar];
if (!webhookUrl) throw new Error(`No Discord webhook URL. Set ${envVar || 'TEST_DISCORD_WEBHOOK_URL'} in .env or discord.webhook_url in jobs/test.json`);

const today = new Date().toISOString().split('T')[0];
const discordBody = JSON.stringify({
  username: config?.discord?.username || 'Test News Bot',
  embeds: [{
    title: `${config?.name || 'Test Digest'} - ${today}`,
    description: summary,
    color: config?.discord?.embed_color || 16711680,
    footer: { text: promptData?.articleTitle || '' }
  }]
});
return [{ json: { webhookUrl, discordBody } }];
